// QueryAssocs queries the assocs edge of a Snapin.
func (c *SnapinClient) QueryAssocs(_m *Snapin) *SnapinAssocQuery {
	query := (&SnapinAssocClient{config: c.config}).Query()
	query.path = func(context.Context) (fromV *sql.Selector, _ error) {
		id := _m.ID
		step := sqlgraph.NewStep(
			sqlgraph.From(snapin.Table, snapin.FieldID, id),
			sqlgraph.To(snapinassoc.Table, snapinassoc.FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, snapin.AssocsTable, snapin.AssocsColumn),
		)
		fromV = sqlgraph.Neighbors(_m.driver.Dialect(), step)
		return fromV, nil
	}
	return query
}

